var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"At the same time","TWN":"同一時間","DEU":"At the same time","FRA":"At the same time"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 대균열","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>大亀裂</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>大峽谷","DEU":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice","FRA":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"네놈들도 참 끈질기군.","JPN":"しつこいぞ、貴様ら。","ENG":"How persistent all of you are.","TWN":"你們還真頑強。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"설마 또다시 내 앞을 가로막을 줄이야.","JPN":"どこまでもこの私の前を立ちはだかるのだな。","ENG":"To think you would stand in my way again.","TWN":"居然又一次擋在我面前。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"천사는 가까이, 하지만 사탄은 더 가까이.","JPN":"天使と親しく、だが悪魔にはもっと親しく。","ENG":"Keep angels close. But the devil closer.","TWN":"天使近在咫尺，但撒旦更近一步。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신도 기억하시겠죠. 요한 추기경이 남긴 가르침입니다.","JPN":"あなたも覚えているはず。ヨハン枢機卿が残した教えです。","ENG":"You remember it, do you not? Cardinal Johan's teaching.","TWN":"你應該還記得吧，約翰樞機主教留下的教誨。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭큭, 기적 심의회의 모토인가? 감회가 새롭군.","JPN":"くくっ、奇跡審議会のモットーか？　感慨深いな。","ENG":"Haha. The Miracle Council's motto, was it? That brings back memories.","TWN":"呵呵，是奇蹟議會的座右銘嗎？真令人感慨。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그 자의 가르침이라면, 이것도 기억하나?","JPN":"あの者の教えといえば、これも覚えているか？","ENG":"Then do you remember his other teaching as well?","TWN":"那你也記得他的這句話嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"의심할 수 없을 때까지 의심해라.","JPN":"疑えなくなるまで疑え。","ENG":"Doubt until thou cannot doubt any more.","TWN":"在深信不疑之前，就持續懷疑。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"허나, 네놈들이 단 한 번이라도 제대로 의심해 본 적 있나?","JPN":"だが、貴様らは一度でも、まともに疑ったことがあるのか？","ENG":"But have you ever truly doubted, even once?","TWN":"但你們真的有好好懷疑過一次嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"대체 무엇이 천사고, 무엇이 사탄이지?","JPN":"いったい何が天使で、何が悪魔だ？","ENG":"Tell me, what is an angel, and what is a devil?","TWN":"究竟什麼是天使，什麼是撒旦？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"사상과 종교가 다른 이를 배척하는 지금의 성황청이 선이라고 생각하나?","JPN":"思想と宗教が異なるという理由で人を押しのける、今の聖皇庁は善だと思うか？","ENG":"Do you truly believe the current Holy Curia, which excludes those of different beliefs and religions, is righteous?","TWN":"排斥思想與信仰不同之人的聖皇廳，真的是善嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"세상의 모든 부조리와 악덕을 방관하는 지금의 신이 선이라고 생각하나?","JPN":"世界に散らばる不条理と悪をただ傍観するだけの神が、善だと思うのか？","ENG":"Do you believe a god who turns a blind eye to all the world's injustice and vice is righteous?","TWN":"對世上一切不公與罪惡袖手旁觀的神，真的是善嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄요, 하지만 한 가지만큼은 틀림이 없겠죠.","JPN":"さあ。ですがこれだけは確かです。","ENG":"Perhaps not. But one thing is certain.","TWN":"也許吧。但至少有一點可以確定。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"광인의 논리로, 함부로 타인을 희생시키려는 당신이 옳을 리 없으니까요.","JPN":"狂人の論理で勝手に他人を犠牲にしようとするあなたが正しいはずがありません。","ENG":"Someone who sacrifices others through a maniac's logic can never be right.","TWN":"用瘋子的邏輯隨意犧牲他人的你，絕對不可能正確。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"참회의 시간은 끝났습니다!","JPN":"懺悔の時間は終わりです！","ENG":"The time for repentance is over.","TWN":"懺悔的時間結束了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"비블리오테카! 구속하라!","JPN":"ビブリオテカ！　拘束せよ！","ENG":"Bibliotheca! Bind!","TWN":"圖書館！拘束！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 이 장소에 미리 종이를 숨겨두었나……!","JPN":"くっ、あらかじめこの場所に紙を隠しておいたか……！","ENG":"Kgh, you hid paper here in advance...?!","TWN":"嘖，事先把紙藏在這裡了嗎……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠, 그건 평범한 종이가 아닙니다.","JPN":"訂正させてもらいましょう。それは普通の紙ではありません。","ENG":"I would be more than happy to rephrase. That is no ordinary paper.","TWN":"容我更正，那不是普通的紙。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오늘의 심판을 위해서, 특별히 엄선해둔 72권의 금서 페이지니까……!","JPN":"今日の審判のために厳選した、72冊の禁書ページですから！","ENG":"These are pages drawn from seventy-two handpicked forbidden books, prepared for today's judgment...!","TWN":"那是為了今日的審判，特別挑選的72本禁書書頁……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"금서라고? 당했군……!","JPN":"禁書だと？　くっ……！","ENG":"Forbidden books? I've been outplayed...!","TWN":"禁書？我被算計了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"화형, 타올라라!","JPN":"火刑、燃えろ！","ENG":"Immolation. Burn!","TWN":"火刑，燃燒吧！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"으아, 으아아아아아악───!!","JPN":"く、くああああああっ——！！","ENG":"Aah– AAAAAARGH───!!","TWN":"啊、啊啊啊啊啊──！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이, 이정도로……!!","JPN":"こ、この程度で……！！","ENG":"N-not yet...!!","TWN":"這、這種程度就……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"척살, 찔러 죽여라!","JPN":"刺殺！　刺し殺せ！","ENG":"Fatal wound. Pierce and kill!","TWN":"斬首！刺殺！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"커헉……!","JPN":"がはっ……！","ENG":"Kuh...!","TWN":"咳啊……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대답하세요. 변절자!","JPN":"答えなさい、変節者！","ENG":"Answer me. Betrayer!","TWN":"回答我，叛徒！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 예하를 살해했죠? 모든 이가 신성에 다다른 다는 건 무슨 뜻입니까!","JPN":"なぜ猊下を手にかけたのです？　すべての者が神聖に到達するというのは、どういう意味ですか！","ENG":"Why did you murder His Eminence? What do you mean by saying everyone shall reach Divinity?!","TWN":"為何殺害部下？「所有人皆能抵達神性」到底是什麼意思！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 신성이라는 건……!","JPN":"そして神聖とは……！","ENG":"And this Divinity...!","TWN":"還有神性究竟是……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"안경 꼰대, 조심해! 뭔가 꾸미고 있어!","JPN":"眼鏡ばばあ、気をつけろ！　やつが何か企んでる！","ENG":"Watch out, Specky Snob! He's up to something!","TWN":"眼鏡老頭，小心！他在搞鬼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"금서의 페이지를 역이용했다고? 그 짧은 시간에 구절을 외웠어?","JPN":"禁書のページを逆手にとった？　あの短時間で本の内容を読み取っただと？","ENG":"You reversed the forbidden book pages? You recited the passage in that short time?","TWN":"反向利用禁書書頁？竟然在那麼短的時間內就背下來了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};